module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

    wire [size-1:0] mul_a_ext;
    wire [size-1:0] mul_b_ext;
    assign mul_a_ext = {size{1'b0}} + mul_a;
    assign mul_b_ext = {size{1'b0}} + mul_b;

    reg [7:0] sum_tmp1;
    reg [7:0] sum_tmp2;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            sum_tmp1 <= 8'b0;
            sum_tmp2 <= 8'b0;
        end else begin
            sum_tmp1 <= (mul_b_ext[0] ? mul_a_ext : 8'b0) + (mul_b_ext[1] ? mul_a_ext << 1 : 8'b0);
            sum_tmp2 <= (mul_b_ext[2] ? mul_a_ext << 2 : 8'b0) + (mul_b_ext[3] ? mul_a_ext << 3 : 8'b0);
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            mul_out <= 8'b0;
        end else begin
            mul_out <= sum_tmp1 + sum_tmp2;
        end
    end
endmodule
